<?php
namespace Tests\Feature;use App\Models\Character;use App\Models\Hunt;use App\Models\User;use App\Models\Zone;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;class CharacterHuntTest extends TestCase{use RefreshDatabase;public function test_owner_posts_with_prg_and_client_monster_is_ignored(){$this->seed(WorldCatalogSeeder::class);$u=User::factory()->create();$c=Character::factory()->for($u)->create();$z=Zone::where('code','grey_oak_forest')->first();$response=$this->actingAs($u)->post(route('characters.hunts.store',[$c,$z]),['monster_id'=>999999]);$hunt=Hunt::firstOrFail();$response->assertRedirect(route('characters.hunts.show',[$c,$hunt->id]));$this->get(route('characters.hunts.show',[$c,$hunt->id]))->assertOk()->assertSee('todavía no entrega');$this->get(route('characters.hunts.index',$c))->assertOk()->assertSee($hunt->monster_name);}public function test_guests_and_other_users_are_blocked(){$this->seed(WorldCatalogSeeder::class);$owner=User::factory()->create();$c=Character::factory()->for($owner)->create();$z=Zone::where('code','grey_oak_forest')->first();$this->post(route('characters.hunts.store',[$c,$z]))->assertRedirect('/login');$this->actingAs(User::factory()->create())->post(route('characters.hunts.store',[$c,$z]))->assertForbidden();}}
